537	
538	.settings-content {
539	  padding: calc(var(--spacing) * 6) calc(var(--spacing) * 8);
540	  overflow-y: auto;
541	}
542	
543	.settings-section {
544	  max-width: 640px;
545	  margin: 0 auto calc(var(--spacing) * 8);
546	}
547	
548	.settings-section__header {
549	  margin-bottom: calc(var(--spacing) * 4);
550	}
551	
552	.settings-section__title {
553	  font-size: calc(var(--text-base) * 1.25);
554	  font-weight: 600;
555	  color: var(--color-text-foreground);
556	}
557	
558	.settings-section__subtitle {
559	  margin-top: calc(var(--spacing) * 1);
560	  font-size: var(--text-sm);
561	  line-height: 1.5;
562	  color: var(--color-text-foreground-tertiary);
563	}
564	
565	.settings-card {
566	  display: flex;
567	  flex-direction: column;
568	  overflow: hidden;
569	  background: var(--color-background-elevated-secondary);
570	  border: 1px solid var(--color-border);
571	  border-radius: 8px;
572	}
573	
574	.settings-row {
575	  display: flex;
576	  gap: calc(var(--spacing) * 4);
577	  align-items: center;
578	  justify-content: space-between;
579	  padding: calc(var(--spacing) * 3) calc(var(--spacing) * 4);
580	  border-bottom: 1px solid var(--color-border-light);
581	}
582	
583	.settings-row:last-child {
584	  border-bottom: 0;
585	}
586	
587	.settings-row__label {
588	  font-size: var(--text-sm);
589	  color: var(--color-text-foreground);
590	}
591	
592	.settings-row__value {
593	  padding: 2px calc(var(--spacing) * 1.5);
594	  font-family: "SF Mono", ui-monospace, Menlo, monospace;
595	  font-size: 0.82rem;
596	  color: var(--color-text-foreground-secondary);
597	  background: var(--color-background-elevated-primary-opaque);
598	  border: 1px solid var(--color-border);
599	  border-radius: 4px;
600	}
601	
602	.switch {
603	  position: relative;
604	  display: inline-flex;
605	  align-items: center;
606	  width: 30px;
607	  height: 18px;
608	  cursor: default;
609	}
610	
611	.switch input {
612	  position: absolute;
613	  inset: 0;
614	  margin: 0;
615	  cursor: inherit;
616	  opacity: 0;
617	}
618	
619	.switch__track {
620	  position: relative;
621	  width: 100%;
622	  height: 100%;
623	  background: var(--color-background-elevated-primary-opaque);
624	  border: 1px solid var(--color-border);
625	  border-radius: 999px;
626	  transition: background 120ms ease;
627	}
628	
629	.switch__track::after {
630	  position: absolute;
631	  top: 1px;
632	  left: 1px;
633	  width: 14px;
634	  height: 14px;
635	  content: "";
636	  background: var(--color-text-foreground);
637	  border-radius: 50%;
638	  transition: transform 140ms ease;
639	}
640	
641	.switch input:checked + .switch__track {
642	  background: var(--color-accent);
643	  border-color: transparent;
644	}
645	
646	.switch input:checked + .switch__track::after {
647	  transform: translateX(12px);
648	}
649	
650	.switch input:disabled + .switch__track {
651	  opacity: 0.5;
652	}
653	
654	.segmented {
655	  display: inline-flex;
656	  padding: 2px;
657	  background: var(--color-background-elevated-primary-opaque);
658	  border: 1px solid var(--color-border);
659	  border-radius: 6px;
660	}
661	
662	.segmented__button {
663	  padding: calc(var(--spacing) * 1) calc(var(--spacing) * 2);
664	  font: inherit;
665	  font-size: var(--text-sm);
666	  color: var(--color-text-foreground-tertiary);
667	  appearance: none;
668	  cursor: default;
669	  background: transparent;
670	  border: 0;
671	  border-radius: 4px;
672	}
673	
674	.segmented__button:hover {
675	  color: var(--color-text-foreground-secondary);
676	}
677	
678	.segmented__button.active {
679	  color: var(--color-text-foreground);
680	  background: var(--color-background-elevated-secondary-opaque);
681	}
682	
683	/* Error overlay */
684	
685	#lightfast-desktop-error-overlay {
686	  position: fixed;
687	  inset: 0;
688	  z-index: 9999;
689	  display: none;
690	  align-items: center;
691	  justify-content: center;
692	  background: color-mix(in oklab, var(--gray-1000) 85%, transparent);
693	}
694	
695	#lightfast-desktop-error-overlay[data-visible="true"] {
696	  display: flex;
697	}
698	
699	.error-overlay__panel {
700	  max-width: 520px;
701	  padding: calc(var(--spacing) * 6) calc(var(--spacing) * 8);
702	  color: var(--color-text-foreground);
703	  background: var(--color-background-elevated-primary-opaque);
704	  border: 1px solid var(--color-border-heavy);
705	  border-radius: 8px;
706	}
707	
708	.error-overlay__panel h2 {
709	  margin: 0 0 calc(var(--spacing) * 3);
710	  font-size: calc(var(--text-base) * 1.3);
711	  font-weight: 600;
712	}
713	
714	.error-overlay__message {
715	  max-height: 200px;
716	  padding: calc(var(--spacing) * 2);
717	  margin: 0 0 calc(var(--spacing) * 4);
718	  overflow: auto;
719	  font-family: "SF Mono", ui-monospace, Menlo, monospace;
720	  font-size: calc(var(--text-sm) * 0.95);
721	  color: var(--color-text-foreground-secondary);
722	  white-space: pre-wrap;
723	  background: var(--color-background-elevated-secondary);
724	  border-radius: 4px;
725	}
726	
727	.error-overlay__reload {
728	  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 4);
729	  font: inherit;
730	  font-size: var(--text-sm);
731	  color: var(--color-text-foreground);
732	  appearance: none;
733	  cursor: default;
734	  background: var(--color-background-elevated-secondary);
735	  border: 1px solid var(--color-border);
736	  border-radius: 6px;
737	}
738	
739	/* Signed-out onboarding overlay — mirrors Codex login layout */
740	
741	.auth-gate {
742	  position: fixed;
743	  inset: 0;
744	  z-index: 10;
745	  display: flex;
746	  flex-direction: column;
747	  overflow: hidden;
748	  background: var(--color-background-surface);
749	  color: var(--color-text-foreground);
750	  -webkit-app-region: drag;
751	}
752	
753	.auth-gate__titlebar-drag {
754	  flex-shrink: 0;
755	  height: var(--height-toolbar);
756	}
757	
758	.auth-gate__content {
759	  flex: 1;
760	  display: flex;
761	  flex-direction: column;
762	  align-items: center;
763	  justify-content: center;
764	  padding: 0 calc(var(--spacing) * 4) calc(var(--spacing) * 6);
765	  -webkit-app-region: no-drag;
766	}
767	
768	.auth-gate__hero {
769	  display: flex;
770	  flex-direction: column;
771	  align-items: center;
772	  gap: calc(var(--spacing) * 8);
773	}
774	
775	.auth-gate__logo {
776	  width: 52px;
777	  height: 52px;
778	  flex-shrink: 0;
779	  color: var(--color-text-foreground);
780	}
781	
782	.auth-gate__title {
783	  margin: 0;
784	  font-size: 28px;
785	  line-height: 36px;
786	  font-weight: 400;
787	  color: var(--color-text-foreground);
788	  text-align: center;
789	  white-space: nowrap;
790	}
791	
792	.auth-gate__actions {
793	  display: flex;
794	  flex-direction: column;
795	  align-items: center;
796	  gap: calc(var(--spacing) * 3);
797	  width: 100%;
798	  max-width: 340px;
799	  margin-top: calc(var(--spacing) * 8);
800	}
801	
802	.auth-gate__primary-button,
803	.auth-gate__secondary-button {
804	  display: flex;
805	  align-items: center;
806	  justify-content: center;
807	  width: 100%;
808	  font-size: 14px;
809	  line-height: 20px;
810	  font-weight: 500;
811	  appearance: none;
812	  cursor: pointer;
813	  border-radius: 9999px;
814	  transition:
815	    background 120ms ease,
816	    border-color 120ms ease,
