819	
820	@media (prefers-reduced-motion: reduce) {
821	  .auth-gate__primary-button,
822	  .auth-gate__secondary-button {
823	    transition: none;
824	  }
825	}
826	
827	.auth-gate__primary-button {
828	  height: 48px;
829	  color: var(--color-background-surface);
830	  background: var(--color-text-foreground);
831	  border: 1px solid transparent;
