file.content:
:root {
  --spacing: 0.25rem;
  --text-base: 13px;
  --text-sm: 12px;
  --height-toolbar: 46px;

  --gray-0: #ffffff;
  --gray-50: #f9f9f9;
  --gray-100: #ededed;
  --gray-300: #afafaf;
  --gray-500: #5d5d5d;
  --gray-600: #414141;
  --gray-750: #282828;
  --gray-800: #212121;
  --gray-900: #181818;
  --gray-1000: #0d0d0d;

  --spacing-token-sidebar: clamp(240px, 300px, min(520px, calc(100vw - 320px)));
  --sidebar-transition: 220ms cubic-bezier(0.4, 0, 0.2, 1);

  --thread-content-max-width: 480px;

  font-family:
    -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
  font-size: var(--text-base);
}

.electron-dark {
  --color-background-surface: var(--gray-900);
  --color-background-surface-under: #000000;
  --color-background-elevated-primary: color-mix(
    in oklab,
    var(--gray-800) 96%,
    transparent
  );
  --color-background-elevated-primary-opaque: var(--gray-750);
  --color-background-elevated-secondary: color-mix(
    in oklab,
    var(--gray-0) 3%,
    transparent
  );
  --color-background-elevated-secondary-opaque: var(--gray-800);
  --color-background-button-tertiary: color-mix(
    in oklab,
    var(--gray-0) 3%,
    transparent
  );
  --color-background-button-tertiary-hover: color-mix(
    in oklab,
    var(--gray-0) 7%,
    transparent
  );
  --color-background-button-tertiary-active: color-mix(
    in oklab,
    var(--gray-0) 10%,
    transparent
  );
  --color-accent: #4f9cff;

  --color-text-foreground: var(--gray-0);
  --color-text-foreground-secondary: color-mix(
    in oklab,
    var(--gray-0) 70%,
    transparent
  );
  --color-text-foreground-tertiary: color-mix(
    in oklab,
    var(--gray-0) 50%,
    transparent
  );

  --color-border: color-mix(in oklab, #ffffff 8%, transparent);
  --color-border-heavy: color-mix(in oklab, #ffffff 16%, transparent);
  --color-border-light: color-mix(in oklab, #ffffff 4%, transparent);
  color-scheme: dark;
}

.electron-light {
  --color-background-surface: var(--gray-50);
  --color-background-surface-under: var(--gray-0);
  --color-background-elevated-primary: color-mix(
    in oklab,
    var(--gray-0) 96%,
    transparent
  );
  --color-background-elevated-primary-opaque: var(--gray-0);
  --color-background-elevated-secondary: color-mix(
    in oklab,
    var(--gray-1000) 4%,
    transparent
  );
  --color-background-elevated-secondary-opaque: var(--gray-100);
  --color-background-button-tertiary: color-mix(
    in oklab,
    var(--gray-1000) 3%,
    transparent
  );
  --color-background-button-tertiary-hover: color-mix(
    in oklab,
    var(--gray-1000) 6%,
    transparent
  );
  --color-background-button-tertiary-active: color-mix(
    in oklab,
    var(--gray-1000) 10%,
    transparent
  );
  --color-accent: #0a66d6;

  --color-text-foreground: var(--gray-1000);
  --color-text-foreground-secondary: color-mix(
    in oklab,
    var(--gray-1000) 70%,
    transparent
  );
  --color-text-foreground-tertiary: color-mix(
    in oklab,
    var(--gray-1000) 50%,
    transparent
  );

  --color-border: color-mix(in oklab, var(--gray-1000) 10%, transparent);
  --color-border-heavy: color-mix(in oklab, var(--gray-1000) 20%, transparent);
  --color-border-light: color-mix(in oklab, var(--gray-1000) 5%, transparent);
  color-scheme: light;
}

html,
body,
#app {
  height: 100%;
  margin: 0;
  color: var(--color-text-foreground);
  background: transparent;
}

#app {
  display: flex;
}

.sidebar {
  display: flex;
  flex-direction: column;
  width: var(--spacing-token-sidebar);
  height: 100%;
  overflow: hidden;
  background: transparent;
  border-right: 1px solid var(--color-border);
  transition:
    width var(--sidebar-transition),
    border-color var(--sidebar-transition);
}

:root[data-sidebar-collapsed="true"] .sidebar {
  width: 0;
  border-right-color: transparent;
}

.content {
  display: flex;
  flex: 1;
  flex-direction: column;
  height: 100%;
  background: var(--color-background-surface);
}

.titlebar-drag {
  -webkit-app-region: drag;
  height: var(--height-toolbar);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  gap: calc(var(--spacing) * 2);
}

:root[data-platform="darwin"] .sidebar .titlebar-drag {
  justify-content: flex-end;
  padding-right: calc(var(--spacing) * 3);
  padding-left: 80px;
}

:root[data-platform="darwin"] .content .titlebar-drag {
  padding-left: calc(var(--spacing) * 3);
}

:root[data-platform="win32"] .content .titlebar-drag {
  padding-right: 138px;
}

.sidebar-trigger,
.content-sidebar-trigger {
  -webkit-app-region: no-drag;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  padding: 0;
  color: var(--color-text-foreground-tertiary);
  appearance: none;
  cursor: default;
  background: transparent;
  border: 1px solid transparent;
  border-radius: 6px;
  transition:
    color 120ms ease,
    background 120ms ease,
    border-color 120ms ease;
}

.sidebar-trigger:hover,
.content-sidebar-trigger:hover {
  color: var(--color-text-foreground);
  background: var(--color-background-button-tertiary-hover);
}

.content-sidebar-trigger {
  display: none;
}

:root[data-sidebar-collapsed="true"] .content-sidebar-trigger {
  display: inline-flex;
}

.nav {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: calc(var(--spacing) * 1) calc(var(--spacing) * 2);
}

.item {
  -webkit-app-region: no-drag;
  display: flex;
  align-items: center;
  gap: calc(var(--spacing) * 2);
  width: 100%;
  height: calc(var(--spacing) * 8);
  padding: 0 calc(var(--spacing) * 2);
  appearance: none;
  background: transparent;
  border: 0;
  border-radius: 8px;
  color: var(--color-text-foreground-secondary);
  font: inherit;
  font-size: var(--text-sm);
  text-align: left;
  cursor: pointer;
  transition:
    background 120ms ease,
    color 120ms ease;
}

.item:hover {
  background: var(--color-background-button-tertiary-hover);
  color: var(--color-text-foreground);
}

.item.active {
  background: var(--color-background-button-tertiary-active);
  color: var(--color-text-foreground);
}

.item__icon {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.item__label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.content-inner {
  display: none;
  padding: calc(var(--spacing) * 6) calc(var(--spacing) * 8);
  color: var(--color-text-foreground-secondary);
}

.content-inner:not(.settings-root) {
  max-width: var(--thread-content-max-width);
}

.settings-root {
  max-width: none;
  padding: 0;
}

:root[data-route="home"] [data-route-home],
:root[data-route="settings"] [data-route-settings] {
  display: revert;
}

:root[data-window-kind="primary"][data-route="home"]
  [data-route-home][data-kind-primary],
:root[data-window-kind="primary"][data-route="settings"]
  [data-route-settings][data-kind-primary] {
  display: revert;
}

:root[data-window-kind="secondary"] [data-kind-secondary],
:root[data-window-kind="hud"] [data-kind-hud] {
  display: revert;
}

:root[data-window-kind="primary"] [data-kind-secondary],
:root[data-window-kind="primary"] [data-kind-hud],
:root[data-window-kind="secondary"] [data-kind-primary],
:root[data-window-kind="secondary"] .sidebar,
:root[data-window-kind="hud"] [data-kind-primary],
:root[data-window-kind="hud"] .sidebar {
  display: none;
}

.content-inner h1 {
  margin: 0 0 calc(var(--spacing) * 3);
  font-size: calc(var(--text-base) * 1.6);
  font-weight: 600;
  color: var(--color-text-foreground);
}

.content-inner p {
  margin: 0 0 calc(var(--spacing) * 3);
  line-height: 1.55;
}

.content-inner p:last-child {
  margin-bottom: 0;
}

.content-hint {
  color: var(--color-text-foreground-tertiary);
}

code,
kbd {
  padding: 1px calc(var(--spacing) * 1);
  font-family: "SF Mono", ui-monospace, Menlo, monospace;
  font-size: 0.92em;
  background: var(--color-background-elevated-secondary);
  border: 1px solid var(--color-border);
  border-radius: 4px;
}

kbd {
  background: var(--color-background-elevated-primary);
}

.actions {
  display: flex;
  gap: calc(var(--spacing) * 2);
  margin-top: calc(var(--spacing) * 4);
}

.action {
  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 3);
  font: inherit;
  font-size: var(--text-sm);
  color: var(--color-text-foreground);
  appearance: none;
  cursor: default;
  background: var(--color-background-elevated-secondary);
  border: 1px solid var(--color-border);
  border-radius: 6px;
}

.action:hover {
  background: var(--color-background-elevated-primary);
  border-color: var(--color-border-heavy);
}

.build-badge {
  margin-top: calc(var(--spacing) * 4);
  font-family: "SF Mono", ui-monospace, Menlo, monospace;
  font-size: calc(var(--text-sm) * 0.9);
  color: var(--color-text-foreground-tertiary);
}

/* Sidebar footer / user menu */

.sidebar-footer {
  margin-top: auto;
  padding: calc(var(--spacing) * 2);
  border-top: 1px solid var(--color-border-light);
}

.user-menu-trigger {
  -webkit-app-region: no-drag;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  padding: 0;
  appearance: none;
  cursor: default;
  background: var(--color-background-button-tertiary);
  border: 1px solid var(--color-border);
  border-radius: 6px;
  transition:
    background 120ms ease,
    border-color 120ms ease;
}

.user-menu-trigger:hover {
  background: var(--color-background-button-tertiary-hover);
  border-color: var(--color-border-heavy);
}

.user-menu-avatar {
  font-size: 11px;
  font-weight: 600;
  line-height: 1;
  color: var(--color-text-foreground-secondary);
}

.user-menu-content {
  min-width: 200px;
  padding: calc(var(--spacing) * 1);
  background: var(--color-background-elevated-primary-opaque);
  border: 1px solid var(--color-border);
  border-radius: 8px;
  box-shadow:
    0 4px 16px color-mix(in oklab, #000 30%, transparent),
    0 1px 4px color-mix(in oklab, #000 15%, transparent);
  animation: user-menu-enter 120ms ease;
  z-index: 100;
}

@keyframes user-menu-enter {
  from {
    opacity: 0;
    transform: translateY(4px) scale(0.97);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.user-menu-label {
  display: flex;
  align-items: center;
  gap: calc(var(--spacing) * 2);
  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 2);
  font-size: var(--text-sm);
  color: var(--color-text-foreground-secondary);
  user-select: none;
}

.user-menu-email {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.user-menu-icon {
  flex-shrink: 0;
  color: var(--color-text-foreground-tertiary);
}

.user-menu-separator {
  height: 1px;
  margin: calc(var(--spacing) * 1) 0;
  background: var(--color-border-light);
}

.user-menu-item {
  display: flex;
  align-items: center;
  gap: calc(var(--spacing) * 2);
  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 2);
  font-size: var(--text-sm);
  color: var(--color-text-foreground);
  border-radius: 6px;
  cursor: default;
  user-select: none;
  outline: none;
}

.user-menu-item[data-highlighted] {
  background: var(--color-background-button-tertiary-hover);
}

.user-menu-item--destructive {
  color: #ef4444;
}

.user-menu-item--destructive .user-menu-icon {
  color: #ef4444;
}

/* Settings */

.settings-host {
  display: grid;
  grid-template-columns: 220px 1fr;
  height: 100%;
  min-height: 0;
}

.settings-nav {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: calc(var(--spacing) * 4);
  overflow-y: auto;
  border-right: 1px solid var(--color-border);
}

.settings-nav__item {
  -webkit-app-region: no-drag;
  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 2.5);
  font: inherit;
  font-size: var(--text-sm);
  text-align: left;
  color: var(--color-text-foreground-secondary);
  appearance: none;
  cursor: default;
  background: transparent;
  border: 0;
  border-radius: 6px;
}

.settings-nav__item:hover {
  background: var(--color-background-button-tertiary-hover);
}

.settings-nav__item.active {
  color: var(--color-text-foreground);
  background: var(--color-background-button-tertiary-active);
}

.settings-content {
  padding: calc(var(--spacing) * 6) calc(var(--spacing) * 8);
  overflow-y: auto;
}

.settings-section {
  max-width: 640px;
  margin: 0 auto calc(var(--spacing) * 8);
}

.settings-section__header {
  margin-bottom: calc(var(--spacing) * 4);
}

.settings-section__title {
  font-size: calc(var(--text-base) * 1.25);
  font-weight: 600;
  color: var(--color-text-foreground);
}

.settings-section__subtitle {
  margin-top: calc(var(--spacing) * 1);
  font-size: var(--text-sm);
  line-height: 1.5;
  color: var(--color-text-foreground-tertiary);
}

.settings-card {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: var(--color-background-elevated-secondary);
  border: 1px solid var(--color-border);
  border-radius: 8px;
}

.settings-row {
  display: flex;
  gap: calc(var(--spacing) * 4);
  align-items: center;
  justify-content: space-between;
  padding: calc(var(--spacing) * 3) calc(var(--spacing) * 4);
  border-bottom: 1px solid var(--color-border-light);
}

.settings-row:last-child {
  border-bottom: 0;
}

.settings-row__label {
  font-size: var(--text-sm);
  color: var(--color-text-foreground);
}

.settings-row__value {
  padding: 2px calc(var(--spacing) * 1.5);
  font-family: "SF Mono", ui-monospace, Menlo, monospace;
  font-size: 0.82rem;
  color: var(--color-text-foreground-secondary);
  background: var(--color-background-elevated-primary-opaque);
  border: 1px solid var(--color-border);
  border-radius: 4px;
}

.switch {
  position: relative;
  display: inline-flex;
  align-items: center;
  width: 30px;
  height: 18px;
  cursor: default;
}

.switch input {
  position: absolute;
  inset: 0;
  margin: 0;
  cursor: inherit;
  opacity: 0;
}

.switch__track {
  position: relative;
  width: 100%;
  height: 100%;
  background: var(--color-background-elevated-primary-opaque);
  border: 1px solid var(--color-border);
  border-radius: 999px;
  transition: background 120ms ease;
}

.switch__track::after {
  position: absolute;
  top: 1px;
  left: 1px;
  width: 14px;
  height: 14px;
  content: "";
  background: var(--color-text-foreground);
  border-radius: 50%;
  transition: transform 140ms ease;
}

.switch input:checked + .switch__track {
  background: var(--color-accent);
  border-color: transparent;
}

.switch input:checked + .switch__track::after {
  transform: translateX(12px);
}

.switch input:disabled + .switch__track {
  opacity: 0.5;
}

.segmented {
  display: inline-flex;
  padding: 2px;
  background: var(--color-background-elevated-primary-opaque);
  border: 1px solid var(--color-border);
  border-radius: 6px;
}

.segmented__button {
  padding: calc(var(--spacing) * 1) calc(var(--spacing) * 2);
  font: inherit;
  font-size: var(--text-sm);
  color: var(--color-text-foreground-tertiary);
  appearance: none;
  cursor: default;
  background: transparent;
  border: 0;
  border-radius: 4px;
}

.segmented__button:hover {
  color: var(--color-text-foreground-secondary);
}

.segmented__button.active {
  color: var(--color-text-foreground);
  background: var(--color-background-elevated-secondary-opaque);
}

/* Error overlay */

#lightfast-desktop-error-overlay {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: none;
  align-items: center;
  justify-content: center;
  background: color-mix(in oklab, var(--gray-1000) 85%, transparent);
}

#lightfast-desktop-error-overlay[data-visible="true"] {
  display: flex;
}

.error-overlay__panel {
  max-width: 520px;
  padding: calc(var(--spacing) * 6) calc(var(--spacing) * 8);
  color: var(--color-text-foreground);
  background: var(--color-background-elevated-primary-opaque);
  border: 1px solid var(--color-border-heavy);
  border-radius: 8px;
}

.error-overlay__panel h2 {
  margin: 0 0 calc(var(--spacing) * 3);
  font-size: calc(var(--text-base) * 1.3);
  font-weight: 600;
}

.error-overlay__message {
  max-height: 200px;
  padding: calc(var(--spacing) * 2);
  margin: 0 0 calc(var(--spacing) * 4);
  overflow: auto;
  font-family: "SF Mono", ui-monospace, Menlo, monospace;
  font-size: calc(var(--text-sm) * 0.95);
  color: var(--color-text-foreground-secondary);
  white-space: pre-wrap;
  background: var(--color-background-elevated-secondary);
  border-radius: 4px;
}

.error-overlay__reload {
  padding: calc(var(--spacing) * 1.5) calc(var(--spacing) * 4);
  font: inherit;
  font-size: var(--text-sm);
  color: var(--color-text-foreground);
  appearance: none;
  cursor: default;
  background: var(--color-background-elevated-secondary);
  border: 1px solid var(--color-border);
  border-radius: 6px;
}

/* Signed-out onboarding overlay — mirrors Codex login layout */

.auth-gate {
  position: fixed;
  inset: 0;
  z-index: 10;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: var(--color-background-surface);
  color: var(--color-text-foreground);
  -webkit-app-region: drag;
}

.auth-gate__titlebar-drag {
  flex-shrink: 0;
  height: var(--height-toolbar);
}

.auth-gate__content {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 0 calc(var(--spacing) * 4) calc(var(--spacing) * 6);
  -webkit-app-region: no-drag;
}

.auth-gate__hero {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: calc(var(--spacing) * 8);
}

.auth-gate__logo {
  width: 52px;
  height: 52px;
  flex-shrink: 0;
  color: var(--color-text-foreground);
}

.auth-gate__title {
  margin: 0;
  font-size: 28px;
  line-height: 36px;
  font-weight: 400;
  color: var(--color-text-foreground);
  text-align: center;
  white-space: nowrap;
}

.auth-gate__actions {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: calc(var(--spacing) * 3);
  width: 100%;
  max-width: 340px;
  margin-top: calc(var(--spacing) * 8);
}

.auth-gate__primary-button,
.auth-gate__secondary-button {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  font-size: 14px;
  line-height: 20px;
  font-weight: 500;
  appearance: none;
  cursor: pointer;
  border-radius: 9999px;
  transition:
    background 120ms ease,
    border-color 120ms ease,
    opacity 120ms ease;
}

@media (prefers-reduced-motion: reduce) {
  .auth-gate__primary-button,
  .auth-gate__secondary-button {
    transition: none;
  }
}

.auth-gate__primary-button {
  height: 48px;
  color: var(--color-background-surface);
  background: var(--color-text-foreground);
  border: 1px solid transparent;
}

.auth-gate__primary-button:hover {
  opacity: 0.8;
}

.auth-gate__secondary-button {
  height: 46px;
  color: var(--color-text-foreground);
  background: transparent;
  border: 1px solid var(--color-border);
}

.auth-gate__secondary-button:hover {
  background: var(--color-background-elevated-secondary);
}

.auth-gate__primary-button:focus-visible,
.auth-gate__secondary-button:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
}

